from __future__ import annotations

from flask import Response


def get_four_chart_dashboard_html_v1() -> Response:
    html = r'''<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>Jack AI Capital OS — 4 Chart Dashboard</title>
  <style>
    :root{--bg:#05070b;--panel:#0b1018;--line:#223044;--text:#e7eef8;--muted:#8794a8;--green:#35d07f;--red:#ff5e6c;--yellow:#f7c948;--blue:#58a6ff}
    *{box-sizing:border-box} body{margin:0;background:var(--bg);color:var(--text);font-family:ui-monospace,SFMono-Regular,Menlo,Consolas,monospace}.wrap{padding:16px;max-width:1680px;margin:0 auto}.top{display:grid;grid-template-columns:1.25fr .75fr;gap:14px;margin-bottom:14px}.panel{background:linear-gradient(180deg,var(--panel),#080c12);border:1px solid var(--line);border-radius:16px;padding:14px;box-shadow:0 18px 40px rgba(0,0,0,.35)}
    .title{display:flex;justify-content:space-between;align-items:flex-start;gap:12px}.h1{font-size:20px;font-weight:900;letter-spacing:.5px}.sub{color:var(--muted);font-size:12px;margin-top:6px;line-height:1.55}.pill{display:inline-flex;align-items:center;border:1px solid var(--line);border-radius:999px;padding:5px 10px;font-size:12px;color:var(--muted);background:#070b11}.command{font-size:36px;font-weight:950;letter-spacing:1px;margin:10px 0 6px}.grid4{display:grid;grid-template-columns:repeat(4,1fr);gap:14px}.chartCard{min-height:360px}.cardHead{display:flex;justify-content:space-between;align-items:center;margin-bottom:8px}.tf{font-size:18px;font-weight:900}.sig{font-size:12px;border-radius:999px;padding:5px 9px;border:1px solid var(--line);color:var(--muted)}.sig.good{color:var(--green);border-color:rgba(53,208,127,.4)}.sig.bad{color:var(--red);border-color:rgba(255,94,108,.4)}.sig.watch{color:var(--yellow);border-color:rgba(247,201,72,.45)}
    .chart{height:210px;background:#05080d;border:1px solid #172335;border-radius:12px;position:relative;overflow:hidden}.chart svg{width:100%;height:100%;display:block}.meta{display:grid;grid-template-columns:repeat(2,1fr);gap:8px;margin-top:10px}.kv{background:#070b12;border:1px solid #172335;border-radius:10px;padding:8px}.k{font-size:10px;color:var(--muted);text-transform:uppercase}.v{font-size:13px;margin-top:4px;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.levels{margin-top:10px;display:flex;gap:8px;flex-wrap:wrap}.level{font-size:11px;color:var(--muted);border:1px solid #172335;border-radius:8px;padding:6px 8px;background:#070b12}.bottom{display:grid;grid-template-columns:.9fr 1.1fr;gap:14px;margin-top:14px}.list{margin:8px 0 0;padding:0;list-style:none}.list li{padding:8px 0;border-bottom:1px solid #172335;color:var(--muted);font-size:12px;line-height:1.45}.bigKpis{display:grid;grid-template-columns:repeat(4,1fr);gap:10px;margin-top:12px}.bigKpi{border:1px solid #172335;border-radius:12px;background:#070b12;padding:10px}.label{color:var(--muted);font-size:10px;text-transform:uppercase}.num{font-size:16px;font-weight:900;margin-top:6px}.toolbar{display:flex;gap:8px;align-items:center;flex-wrap:wrap;margin-top:12px}input,button{background:#070b12;color:var(--text);border:1px solid var(--line);border-radius:10px;padding:9px 10px;font-family:inherit}button{cursor:pointer}button:hover{border-color:var(--blue)}.warn{color:var(--yellow)}.green{color:var(--green)}.red{color:var(--red)}.muted{color:var(--muted)}
    @media(max-width:1100px){.grid4{grid-template-columns:repeat(2,1fr)}.top,.bottom{grid-template-columns:1fr}.bigKpis{grid-template-columns:repeat(2,1fr)}}@media(max-width:640px){.grid4{grid-template-columns:1fr}.command{font-size:26px}}
  </style>
</head>
<body>
  <div class="wrap"><div class="top"><div class="panel"><div class="title"><div><div class="h1">JACK AI CAPITAL OS — 4 CHART DASHBOARD</div><div class="sub">Personal research support only · no broker connection · no auto trading · final decision is manual.</div></div><span class="pill" id="statusPill">LOADING</span></div><div id="command" class="command muted">LOADING...</div><div id="reason" class="sub">Reading readiness engine...</div><div class="bigKpis"><div class="bigKpi"><div class="label">Readiness</div><div class="num" id="readinessScore">—</div></div><div class="bigKpi"><div class="label">Strategy</div><div class="num" id="strategyId">—</div></div><div class="bigKpi"><div class="label">Direction</div><div class="num" id="direction">—</div></div><div class="bigKpi"><div class="label">Next Action</div><div class="num" id="nextAction" style="font-size:12px;line-height:1.35">—</div></div></div><div class="toolbar"><input id="symbolInput" value="GBPJPY" /><button onclick="loadAll(true)">Refresh</button><button onclick="saveSnapshot(true)">Save Now</button><span class="pill" id="autoPill">AUTO SAVE ON · 30s</span><span class="muted" id="updatedAt"></span><span class="muted" id="saveStatus"></span></div></div><div class="panel"><div class="h1">REFERENCE CONTEXT</div><div class="bigKpis" style="grid-template-columns:repeat(2,1fr)"><div class="bigKpi"><div class="label">Trigger Ref</div><div class="num" id="entryPrice">—</div></div><div class="bigKpi"><div class="label">Distance</div><div class="num" id="distancePips">—</div></div><div class="bigKpi"><div class="label">Yesterday High</div><div class="num" id="yHigh">—</div></div><div class="bigKpi"><div class="label">Yesterday Low</div><div class="num" id="yLow">—</div></div></div></div></div><div class="grid4" id="chartGrid"></div><div class="bottom"><div class="panel"><div class="h1">BLOCKERS</div><ul class="list" id="blockers"></ul></div><div class="panel"><div class="h1">REASONS / SIGNAL NOTES</div><ul class="list" id="reasons"></ul></div></div></div>
<script>
let LAST_READY=null,LAST_SAVED_KEY=localStorage.getItem('jack_last_saved_key')||'';const TF_ORDER=['D1','H1','M15','M5'];
function clsFor(text){text=String(text||'').toLowerCase();if(text.includes('long')||text.includes('trend')||text.includes('confirm')||text.includes('ready'))return'good';if(text.includes('wait')||text.includes('unclear')||text.includes('range')||text.includes('blocked')||text.includes('no_trade'))return'bad';if(text.includes('setup')||text.includes('watch')||text.includes('prepare'))return'watch';return''}
function colorForCommand(cmd){cmd=String(cmd||'');if(cmd.includes('READY'))return'green';if(cmd.includes('WATCH')||cmd.includes('PREPARE'))return'warn';if(cmd.includes('WAIT')||cmd.includes('NO')||cmd.includes('DEFENSE'))return'red';return'muted'}function fmt(v){return(v===null||v===undefined||v==='')?'—':v}
function candleChart(candles){if(!candles||!candles.length)return'<div class="muted" style="padding:16px">No candles</div>';const data=candles.slice(-60),highs=data.map(c=>+c.high),lows=data.map(c=>+c.low),max=Math.max(...highs),min=Math.min(...lows),span=(max-min)||1,w=600,h=210,p=14,step=(w-p*2)/data.length;let parts=['<svg viewBox="0 0 '+w+' '+h+'" preserveAspectRatio="none">'];for(let i=0;i<6;i++){let y=p+i*(h-p*2)/5;parts.push(`<line x1="0" y1="${y}" x2="${w}" y2="${y}" stroke="#101a28" stroke-width="1"/>`)}data.forEach((c,i)=>{let x=p+i*step+step/2,o=+c.open,hi=+c.high,lo=+c.low,cl=+c.close,yH=p+(max-hi)/span*(h-p*2),yL=p+(max-lo)/span*(h-p*2),yO=p+(max-o)/span*(h-p*2),yC=p+(max-cl)/span*(h-p*2),up=cl>=o,col=up?'#35d07f':'#ff5e6c',top=Math.min(yO,yC),bh=Math.max(2,Math.abs(yC-yO));parts.push(`<line x1="${x}" y1="${yH}" x2="${x}" y2="${yL}" stroke="${col}" stroke-width="1"/>`);parts.push(`<rect x="${x-step*.28}" y="${top}" width="${Math.max(2,step*.56)}" height="${bh}" fill="${col}" opacity=".9"/>`)});parts.push('</svg>');return parts.join('')}
function tfLabel(tf,sig){if(tf==='D1')return sig.signal;if(tf==='H1')return sig.regime;return sig.signal}
function snapshotKey(r){const s=((r.four_timeframe_signals||{}).signals)||{},t=tf=>((s[tf]||{}).latest_timestamp||'');return[(r.symbol||'GBPJPY'),r.final_command,r.readiness_stage,r.readiness_score,t('D1'),t('H1'),t('M15'),t('M5')].join('|')}
async function loadAll(forceSave=false){const symbol=document.getElementById('symbolInput').value||'GBPJPY';document.getElementById('statusPill').textContent='LOADING';const [readyRes,candleRes]=await Promise.all([fetch(`/api/jack-brain/trade-readiness-v2?symbol=${encodeURIComponent(symbol)}&start_equity=500&target_equity=100000&current_equity=500&peak_equity=500&elapsed_days=0&total_days=365&consecutive_losses=0&news_risk=low`),fetch(`/api/jack-brain/latest-candles-v1?symbol=${encodeURIComponent(symbol)}&timeframes=D1,H1,M15,M5&limit=80`)]);const ready=await readyRes.json();const candles=await candleRes.json();LAST_READY=ready;const cmd=ready.final_command||'UNKNOWN';document.getElementById('command').textContent=cmd;document.getElementById('command').className='command '+colorForCommand(cmd);document.getElementById('statusPill').textContent=ready.readiness_stage||'—';document.getElementById('reason').textContent=ready.reason||'';document.getElementById('readinessScore').textContent=fmt(ready.readiness_score);document.getElementById('strategyId').textContent=fmt(ready.selected_strategy_id);document.getElementById('direction').textContent=fmt(ready.direction==='none'?'No valid direction':ready.direction);document.getElementById('nextAction').textContent=fmt(ready.next_action);const ec=ready.entry_context||{};document.getElementById('entryPrice').textContent=fmt(ec.entry_price);document.getElementById('distancePips').textContent=ec.distance_to_entry_pips==null?'—':ec.distance_to_entry_pips+' pips';document.getElementById('yHigh').textContent=fmt(ec.yesterday_high);document.getElementById('yLow').textContent=fmt(ec.yesterday_low);const signals=(ready.four_timeframe_signals||{}).signals||{},grid=document.getElementById('chartGrid');grid.innerHTML='';TF_ORDER.forEach(tf=>{const sig=signals[tf]||{},tfCandles=(((candles.timeframes||{})[tf]||{}).candles)||[],label=tfLabel(tf,sig)||'—';const card=document.createElement('div');card.className='panel chartCard';card.innerHTML=`<div class="cardHead"><div class="tf">${tf}</div><div class="sig ${clsFor(label)}">${label}</div></div><div class="chart">${candleChart(tfCandles)}</div><div class="meta"><div class="kv"><div class="k">Close</div><div class="v">${fmt(sig.latest_close)}</div></div><div class="kv"><div class="k">Time</div><div class="v">${fmt(sig.latest_timestamp)}</div></div><div class="kv"><div class="k">Bias/Direction</div><div class="v">${fmt(sig.bias||sig.trend_direction||sig.direction)}</div></div><div class="kv"><div class="k">Reference/Distance</div><div class="v">${fmt(sig.entry_price)} / ${sig.distance_to_entry_pips==null?'—':sig.distance_to_entry_pips+'p'}</div></div></div><div class="levels"><span class="level">YH ${fmt(sig.yesterday_high||ec.yesterday_high)}</span><span class="level">YL ${fmt(sig.yesterday_low||ec.yesterday_low)}</span><span class="level">EMA50 ${fmt(sig.ema50)}</span><span class="level">BB Mid ${fmt(sig.bb_middle)}</span></div>`;grid.appendChild(card)});const blockers=document.getElementById('blockers');blockers.innerHTML='';(ready.blockers||['No blockers']).forEach(x=>{const li=document.createElement('li');li.textContent=x;blockers.appendChild(li)});const reasons=document.getElementById('reasons');reasons.innerHTML='';(ready.reasons||['No reasons']).forEach(x=>{const li=document.createElement('li');li.textContent=x;reasons.appendChild(li)});document.getElementById('updatedAt').textContent='Updated '+new Date().toLocaleString();await autoSaveIfChanged(forceSave)}
async function saveSnapshot(force=false){if(!LAST_READY){document.getElementById('saveStatus').textContent='Load first';return}const key=snapshotKey(LAST_READY);if(!force&&key===LAST_SAVED_KEY){document.getElementById('saveStatus').textContent='No change · not saved';return}const tf=LAST_READY.four_timeframe_summary||{};const content=`${LAST_READY.symbol||'GBPJPY'} auto snapshot: command=${LAST_READY.final_command}, stage=${LAST_READY.readiness_stage}, score=${LAST_READY.readiness_score}. D1=${tf.D1}, H1=${tf.H1}, M15=${tf.M15}, M5=${tf.M5}. ${LAST_READY.reason||''}`;const body={memory_type:'dashboard_auto_snapshot',symbol:LAST_READY.symbol||'GBPJPY',title:`Auto Snapshot ${LAST_READY.final_command||''}`,content,tags:['dashboard_auto_snapshot',LAST_READY.final_command||'',LAST_READY.readiness_stage||''],source:'four_chart_dashboard_v1',metadata:{snapshot_key:key,summary:LAST_READY.four_timeframe_summary,score:LAST_READY.readiness_score,blockers:LAST_READY.blockers,reasons:LAST_READY.reasons}};document.getElementById('saveStatus').textContent='Auto saving...';const res=await fetch('/api/jack-brain/save-memory-v1',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(body)});const data=await res.json();if(data.ok){LAST_SAVED_KEY=key;localStorage.setItem('jack_last_saved_key',key);document.getElementById('saveStatus').textContent='Auto saved '+new Date().toLocaleTimeString()}else{document.getElementById('saveStatus').textContent='Auto save failed'}}
async function autoSaveIfChanged(force=false){try{await saveSnapshot(force)}catch(e){document.getElementById('saveStatus').textContent='Auto save error'}}
loadAll(true).catch(err=>{document.getElementById('command').textContent='ERROR';document.getElementById('reason').textContent=String(err)});setInterval(()=>loadAll(false),30000);
</script></body></html>'''
    return Response(html, mimetype="text/html")
